# สคริปต์นี้เขียนทับไฟล์ src\face_analytics.py ด้วยเนื้อหาเวอร์ชันล่าสุด (encode เป็น base64 กัน encoding เพี้ยน)
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes("src\face_analytics.py", $bytes)
Write-Host "เขียนไฟล์ src\face_analytics.py เรียบร้อยแล้ว ($($bytes.Length) bytes)"

# ลบ __pycache__ กันแคชเก่าค้าง
if (Test-Path "__pycache__") { Remove-Item -Recurse -Force "__pycache__" }
if (Test-Path "src\__pycache__") { Remove-Item -Recurse -Force "src\__pycache__" }
Write-Host "ลบ __pycache__ เรียบร้อยแล้ว"

# ยืนยันว่าไฟล์ใหม่ไม่มี NotImplementedError อีกต่อไป
$check = Select-String -Path "src\face_analytics.py" -Pattern "NotImplementedError"
if ($check) {
    Write-Host "[WARNING] ยังเจอ NotImplementedError อยู่ ลองตรวจสอบไฟล์อีกครั้ง" -ForegroundColor Red
} else {
    Write-Host "[OK] ไฟล์ถูกอัปเดตเรียบร้อย พร้อมรัน python main.py ได้เลย" -ForegroundColor Green
}
